/* bundle.min.js - Minified, combined JS with defer loading */
/* Optimizations: removed dead code, combined files, uses IntersectionObserver, no polling */

(function(){'use strict';
// Navbar
var navbar=document.querySelector('.navbar');
var hamburger=document.querySelector('.hamburger');
var navLinks=document.querySelector('.nav-links');
if(navbar){
window.addEventListener('scroll',function(){navbar.classList.toggle('scrolled',window.scrollY>50)},{passive:true});
}
if(hamburger&&navLinks){
hamburger.addEventListener('click',function(){
var isOpen=navLinks.style.display==='flex';
navLinks.style.cssText=isOpen?'':'display:flex;flex-direction:column;position:absolute;top:100%;left:0;right:0;background:#fff;padding:2rem;box-shadow:0 10px 30px rgba(0,0,0,.1);z-index:999';
});
}

// Scroll animations with IntersectionObserver (OPTIMIZED - no scroll handler)
var animEls=document.querySelectorAll('.feature-card,.testimonial-card,.team-card,.portfolio-item,.mv-card,.showcase-item,.award-item');
animEls.forEach(function(el,i){el.classList.add('animate-on-scroll','delay-'+(i%3+1));});
if('IntersectionObserver' in window){
var observer=new IntersectionObserver(function(entries){
entries.forEach(function(e){if(e.isIntersecting){e.target.classList.add('animated');observer.unobserve(e.target);}});
},{threshold:0.1});
animEls.forEach(function(el){observer.observe(el);});
}

// Counter animation with IntersectionObserver
function animCount(el){
var target=parseInt(el.dataset.target),dur=1800,step=target/(dur/16),cur=0;
var t=setInterval(function(){cur+=step;if(cur>=target){cur=target;clearInterval(t);}el.textContent=Math.floor(cur);},16);
}
var counters=document.querySelectorAll('.stat-num,.result-num');
if('IntersectionObserver' in window&&counters.length){
var cObs=new IntersectionObserver(function(entries){
entries.forEach(function(e){if(e.isIntersecting&&!e.target.dataset.done){e.target.dataset.done=1;animCount(e.target);}});
},{threshold:0.5});
counters.forEach(function(c){cObs.observe(c);});
}

// Portfolio filter
var filterBtns=document.querySelectorAll('.filter-btn');
var pItems=document.querySelectorAll('.portfolio-item');
filterBtns.forEach(function(btn){
btn.addEventListener('click',function(){
filterBtns.forEach(function(b){b.classList.remove('active');});
btn.classList.add('active');
var f=btn.dataset.filter;
pItems.forEach(function(item){item.style.display=(f==='all'||item.dataset.category===f)?'block':'none';});
});
});

// FAQ accordion
window.toggleFaq=function(el){
var item=el.parentElement;
document.querySelectorAll('.faq-item').forEach(function(i){if(i!==item)i.classList.remove('open');});
item.classList.toggle('open');
};

// Contact form
var form=document.getElementById('contactForm');
if(form){
form.addEventListener('submit',function(e){
e.preventDefault();
var valid=true;
form.querySelectorAll('[required]').forEach(function(f){
if(!f.value.trim()){f.style.borderColor='#ef4444';valid=false;}
else f.style.borderColor='#22c55e';
});
if(!valid)return;
var btn=form.querySelector('button[type="submit"]');
btn.textContent='Sending...';btn.disabled=true;
setTimeout(function(){
btn.textContent='✓ Sent!';btn.style.background='linear-gradient(135deg,#22c55e,#16a34a)';
setTimeout(function(){btn.textContent='Send Message →';btn.style.background='';btn.disabled=false;form.reset();},3000);
},1500);
});
}

// Smooth scroll for anchor links
document.querySelectorAll('a[href^="#"]').forEach(function(a){
a.addEventListener('click',function(e){
var target=document.querySelector(a.getAttribute('href'));
if(target){e.preventDefault();target.scrollIntoView({behavior:'smooth'});}
});
});
})();
